import{_ as t,c as i,o as a,ax as o}from"./chunks/framework.DHqKNX4U.js";const g=JSON.parse('{"title":"Retention Policy: Lifecycle Worker","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-policy/lifecycle-worker.md","filePath":"enterprise/retention-policy/lifecycle-worker.md"}'),r={name:"enterprise/retention-policy/lifecycle-worker.md"};function l(n,e,s,d,c,h){return a(),i("div",null,e[0]||(e[0]=[o(`<h1 id="retention-policy-lifecycle-worker" tabindex="-1">Retention Policy: Lifecycle Worker <a class="header-anchor" href="#retention-policy-lifecycle-worker" aria-label="Permalink to &quot;Retention Policy: Lifecycle Worker&quot;">​</a></h1><p>The lifecycle worker is the automated enforcement component of the retention policy engine. It runs as a BullMQ background worker that periodically scans all archived emails, evaluates them against active retention policies, and permanently deletes emails that have exceeded their retention period.</p><h2 id="location" tabindex="-1">Location <a class="header-anchor" href="#location" aria-label="Permalink to &quot;Location&quot;">​</a></h2><p><code>packages/enterprise/src/workers/lifecycle.worker.ts</code></p><h2 id="how-it-works" tabindex="-1">How It Works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How It Works&quot;">​</a></h2><h3 id="scheduling" tabindex="-1">Scheduling <a class="header-anchor" href="#scheduling" aria-label="Permalink to &quot;Scheduling&quot;">​</a></h3><p>The lifecycle worker is registered as a repeatable BullMQ cron job on the <code>compliance-lifecycle</code> queue. It is scheduled to run daily at <strong>02:00 UTC</strong> by default. The cron schedule is configured via:</p><div class="language-typescript vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">repeat</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">	pattern</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;0 2 * * *&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">} </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// daily at 02:00 UTC</span></span></code></pre></div><p>The <code>scheduleLifecycleJob()</code> function is called once during enterprise application startup to register the repeatable job with BullMQ.</p><h3 id="batch-processing" tabindex="-1">Batch Processing <a class="header-anchor" href="#batch-processing" aria-label="Permalink to &quot;Batch Processing&quot;">​</a></h3><p>To avoid loading the entire <code>archived_emails</code> table into memory, the worker processes emails in configurable batches:</p><ol><li><strong>Batch size</strong> is controlled by the <code>RETENTION_BATCH_SIZE</code> environment variable.</li><li>Emails are ordered by <code>archivedAt</code> ascending.</li><li>The worker iterates through batches using offset-based pagination until an empty batch is returned, indicating all emails have been processed.</li></ol><h3 id="per-email-processing-flow" tabindex="-1">Per-Email Processing Flow <a class="header-anchor" href="#per-email-processing-flow" aria-label="Permalink to &quot;Per-Email Processing Flow&quot;">​</a></h3><p>For each email in a batch, the worker:</p><ol><li><p><strong>Extracts metadata:</strong> Builds a <code>PolicyEvaluationRequest</code> from the email&#39;s database record:</p><ul><li><code>sender</code>: The sender email address.</li><li><code>recipients</code>: All To, CC, and BCC recipient addresses.</li><li><code>subject</code>: The email subject line.</li><li><code>attachmentTypes</code>: File extensions (e.g., <code>.pdf</code>) extracted from attachment filenames via a join query.</li><li><code>ingestionSourceId</code>: The UUID of the ingestion source that archived this email.</li></ul></li><li><p><strong>Evaluates policies:</strong> Passes the metadata to <code>RetentionService.evaluateEmail()</code>, which returns:</p><ul><li><code>appliedRetentionDays</code>: The longest matching retention period (0 if no policy matches).</li><li><code>matchingPolicyIds</code>: UUIDs of all matching policies.</li></ul></li><li><p><strong>Checks for expiry:</strong></p><ul><li>If <code>appliedRetentionDays === 0</code>, no policy matched — the email is <strong>skipped</strong> (not deleted).</li><li>Otherwise, the email&#39;s age is calculated from its <code>sentAt</code> date.</li><li>If the age in days exceeds <code>appliedRetentionDays</code>, the email has expired.</li></ul></li><li><p><strong>Deletes expired emails:</strong> Calls <code>ArchivedEmailService.deleteArchivedEmail()</code> with:</p><ul><li><code>systemDelete: true</code> — Bypasses the <code>ENABLE_DELETION</code> configuration guard so retention enforcement always works regardless of that global setting.</li><li><code>governingRule</code> — A string listing the matching policy IDs for the audit log entry (e.g., <code>&quot;Policy IDs: abc-123, def-456&quot;</code>).</li></ul></li><li><p><strong>Logs the deletion:</strong> A structured log entry records the email ID and its age in days.</p></li></ol><h3 id="error-handling" tabindex="-1">Error Handling <a class="header-anchor" href="#error-handling" aria-label="Permalink to &quot;Error Handling&quot;">​</a></h3><p>If processing a specific email fails (e.g., due to a database error or storage issue), the error is logged and the worker continues to the next email in the batch. This ensures that a single problematic email does not block the processing of the remaining emails.</p><p>If the entire job fails, BullMQ records the failure and the job ID and error are logged. Failed jobs are retained (up to 50) for debugging.</p><h2 id="system-actor" tabindex="-1">System Actor <a class="header-anchor" href="#system-actor" aria-label="Permalink to &quot;System Actor&quot;">​</a></h2><p>Automated deletions are attributed to a synthetic system actor in the audit log:</p><table tabindex="0"><thead><tr><th>Field</th><th>Value</th></tr></thead><tbody><tr><td>ID</td><td><code>system:lifecycle-worker</code></td></tr><tr><td>Email</td><td><code>system@open-archiver.internal</code></td></tr><tr><td>Name</td><td>System Lifecycle Worker</td></tr><tr><td>Actor IP</td><td><code>system</code></td></tr></tbody></table><p>This well-known identifier can be filtered in the <a href="./../audit-log/">Audit Log</a> to view all retention-based deletions.</p><h2 id="audit-trail" tabindex="-1">Audit Trail <a class="header-anchor" href="#audit-trail" aria-label="Permalink to &quot;Audit Trail&quot;">​</a></h2><p>Every email deleted by the lifecycle worker produces an audit log entry with:</p><ul><li><strong>Action type:</strong> <code>DELETE</code></li><li><strong>Target type:</strong> <code>ArchivedEmail</code></li><li><strong>Target ID:</strong> The UUID of the deleted email</li><li><strong>Actor:</strong> <code>system:lifecycle-worker</code></li><li><strong>Details:</strong> Includes <code>reason: &quot;RetentionExpiration&quot;</code> and <code>governingRule</code> listing the matching policy IDs</li></ul><p>This ensures that every automated deletion is fully traceable back to the specific policies that triggered it.</p><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Environment Variable</th><th>Description</th><th>Default</th></tr></thead><tbody><tr><td><code>RETENTION_BATCH_SIZE</code></td><td>Number of emails to process per batch iteration.</td><td>—</td></tr></tbody></table><h2 id="bullmq-worker-settings" tabindex="-1">BullMQ Worker Settings <a class="header-anchor" href="#bullmq-worker-settings" aria-label="Permalink to &quot;BullMQ Worker Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Setting</th><th>Value</th><th>Description</th></tr></thead><tbody><tr><td>Queue name</td><td><code>compliance-lifecycle</code></td><td>The BullMQ queue name.</td></tr><tr><td>Job ID</td><td><code>lifecycle-daily</code></td><td>Stable job ID for the repeatable cron job.</td></tr><tr><td><code>removeOnComplete</code></td><td>Keep last 10</td><td>Completed jobs retained for monitoring.</td></tr><tr><td><code>removeOnFail</code></td><td>Keep last 50</td><td>Failed jobs retained for debugging.</td></tr></tbody></table><h2 id="integration-with-deletion-guard" tabindex="-1">Integration with Deletion Guard <a class="header-anchor" href="#integration-with-deletion-guard" aria-label="Permalink to &quot;Integration with Deletion Guard&quot;">​</a></h2><p>The core <code>ArchivedEmailService.deleteArchivedEmail()</code> method includes a deletion guard controlled by the <code>ENABLE_DELETION</code> system setting. When called with <code>systemDelete: true</code>, the lifecycle worker bypasses this guard. This design ensures that:</p><ul><li>Manual user deletions can be disabled organization-wide via the system setting.</li><li>Automated retention enforcement always operates regardless of that setting, because retention compliance is a legal obligation that cannot be paused by a UI toggle.</li></ul>`,33)]))}const u=t(r,[["render",l]]);export{g as __pageData,u as default};
